#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ; 
}
inline int Min(int x,int y){return x<y?x:y;}
inline int Max(int x,int y){return x>y?x:y;}
inline int Abs(int x){return x>=0?x:-x;}
const int N=1e6+10,M=2e6+10,INF=0x3f3f3f3f;
struct Graph
{
	int head[N],nxt[M],des[M],cap[M],cnt;
	inline void ins(int x,int y,int z){des[++cnt]=y;cap[cnt]=z;nxt[cnt]=head[x];head[x]=cnt;}
	inline void add(int x,int y,int z){ins(x,y,z);ins(y,x,0);}
	inline void Init(){memset(head,0,sizeof(head));cnt=1;}
}a;
int que[N],H,T,s,t,dep[N];bool vis[N];

inline bool bfs()
{
	memset(dep,0,sizeof(dep));dep[que[H=T=1]=s]=1;
	while(H<=T){int u=que[H++];grep(a,u,i){int v=a.des[i];if(a.cap[i]&&!dep[v])dep[que[++T]=v]=dep[u]+1;}}return dep[t];
}
int dfs(int u,int in)
{
	if(u==t)return in;int out=0;grep(a,u,i)
	{
		int v=a.des[i];if(a.cap[i]&&dep[v]==dep[u]+1)
		{
			int tmp=dfs(v,Min(in,a.cap[i]));
			a.cap[i]-=tmp;in-=tmp;a.cap[i^1]+=tmp;out+=tmp;
		}	if(!in)break;
	}
	if(!out)dep[u]=0;return out;
}
inline int dinic(int u,int v){s=u;t=v;int res=0;while(bfs())res+=dfs(s,INF);return res;}
inline bool isp(int k){for(int i=2;i*i<=k;++i){if(k%i==0)return 0;}return k>2;}
int q[N],b[N],pp;
int main()
{
	a.Init();int n=read();rep(1,n,i)q[i]=read();b[pp=1]=q[1];
	rep(2,n,i)q[i]-q[i-1]>1?(b[++pp]=q[i-1]+1,b[++pp]=q[i]):0;b[++pp]=q[n]+1;
	int nj=0,no=0;rep(1,pp,i)
	{
		if(b[i]&1)
		{
			a.add(pp+1,i,1);++nj;
			rep(1,pp,j)isp(Abs(b[j]-b[i]))?a.add(i,j,1):void(0);
		}
		else a.add(i,pp+2,1),++no;
	}
	int ans=dinic(pp+1,pp+2);//printf("%d %d\n",ans,nj,no);
	printf("%d\n",ans+(nj-ans-((nj-ans)&1))+(no-ans-((no-ans)&1))+3*((no-ans)&1));
}
